use std::{hint::black_box, time::Duration};

use criterion::{BenchmarkId, Criterion, Throughput, criterion_group, criterion_main};
use path_tree::{Folder, Node};

// -------- data generators --------

fn gen_paths(count: usize, depth_min: usize, depth_max: usize) -> Vec<(String, i32)> {
    let mut out = Vec::with_capacity(count);
    for i in 0..count {
        let depth = depth_min + (i % (depth_max - depth_min + 1));
        let mut parts = Vec::with_capacity(depth + 1);
        for d in 0..depth {
            parts.push(format!("d{}", (i + d) % 97));
        }
        parts.push(format!("file{}", i));
        out.push((parts.join("/"), i as i32));
    }
    out
}

// -------- bench groups --------

fn bench_from_vec(c: &mut Criterion) {
    let sizes = [100, 1000, 10_000];
    let mut group = c.benchmark_group("from_vec");
    group.sample_size(40);
    group.warm_up_time(Duration::from_millis(500));
    group.measurement_time(Duration::from_secs(6));

    for &size in &sizes {
        let data = gen_paths(size, 2, 5);
        group.throughput(Throughput::Elements(size as u64));
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, _| {
            b.iter(|| black_box(Folder::from_vec(data.clone())))
        });
    }
    group.finish();
}

fn bench_get(c: &mut Criterion) {
    let mut group = c.benchmark_group("get");
    group.sample_size(100);
    group.warm_up_time(Duration::from_millis(200));

    // shallow: top-level keys
    let size = 200;
    let data: Vec<_> = (0..size).map(|i| (format!("leaf{}", i), i)).collect();
    let folder = Folder::from_vec(data);
    let samples: Vec<String> = (0..50)
        .map(|i| format!("leaf{}", (i * 17) % size))
        .collect();
    group.throughput(Throughput::Elements(50));
    group.bench_function("shallow", |b| {
        b.iter(|| {
            for p in &samples {
                black_box(folder.get(p.as_str()));
            }
        })
    });

    // deep: nested paths
    let size = 50;
    let data = gen_paths(size, 12, 16);
    let folder = Folder::from_vec(data.clone());
    let paths: Vec<String> = data.into_iter().map(|(p, _)| p).collect();
    group.throughput(Throughput::Elements(size as u64));
    group.bench_function("deep", |b| {
        b.iter(|| {
            for p in &paths {
                black_box(folder.get(p.as_str()));
            }
        })
    });
    group.finish();
}

fn bench_entry(c: &mut Criterion) {
    let mut group = c.benchmark_group("entry");
    group.sample_size(80);
    group.warm_up_time(Duration::from_millis(200));
    group.measurement_time(Duration::from_secs(4));

    let base = Folder::from_vec(gen_paths(500, 1, 3));
    let new_paths = gen_paths(200, 2, 4);
    group.bench_function("or_insert", |b| {
        b.iter(|| {
            let mut f = base.clone();
            for (p, v) in &new_paths {
                f.entry(p).unwrap().or_insert(Node::Item(*v));
            }
            black_box(f);
        })
    });

    let existing = gen_paths(200, 1, 3);
    group.bench_function("and_modify", |b| {
        b.iter(|| {
            let mut f = base.clone();
            for (p, _) in &existing {
                f.entry(p)
                    .unwrap()
                    .and_modify(|n| {
                        if let Node::Item(v) = n {
                            *v += 1;
                        }
                    })
                    .or_insert(Node::Item(0));
            }
            black_box(f);
        })
    });

    let ops = gen_paths(200, 1, 4);
    group.bench_function("insert_replace", |b| {
        b.iter(|| {
            let mut f1 = base.clone();
            for (p, v) in &ops {
                f1.insert(p, Node::Item(*v));
            }
            let mut f2 = base.clone();
            for (p, v) in &ops {
                f2.entry(p).unwrap().insert_entry(Node::Item(*v));
            }
            black_box((f1, f2));
        })
    });
    group.finish();
}

