fn bench_iter(c: &mut Criterion) {
    let mut group = c.benchmark_group("iter");
    group.sample_size(100);
    group.warm_up_time(Duration::from_millis(200));

    let folder = Folder::from_vec((0..500).map(|i| (format!("node{i}"), i)).collect());
    group.bench_function("direct", |b| {
        b.iter(|| {
            let mut acc = 0usize;
            for (name, node) in folder.iter() {
                acc = acc.wrapping_add(name.len());
                acc = acc.wrapping_add(if node.is_item() { 1 } else { 0 });
                black_box((name, node));
            }
            black_box(acc);
        })
    });

    let mut data = Vec::new();
    for i in 0..200 {
        for j in 0..3 {
            data.push((format!("g{}/h{}/f{}", i, j, i + j), i + j));
        }
    }
    let folder_rec = Folder::from_vec(data);
    group.bench_function("recursive", |b| {
        b.iter(|| {
            let mut acc = 0usize;
            for (p, node) in folder_rec.iter_recursively() {
                acc = acc.wrapping_add(p.len());
                acc = acc.wrapping_add(if node.is_item() { 1 } else { 0 });
                black_box((&p, node));
            }
            black_box(acc);
        })
    });
    group.finish();
}

